patch:
--- a/priority_encoder.v
+++ b/priority_encoder.v
@@ -6,7 +6,7 @@
   output reg [3:0] priority_out
 );

-  always @(req_bits)
+  always @(*)
   begin
     if (req_bits[15]) priority_out = 4'hF;
     else if (req_bits[14]) priority_out = 4'hE;

before_code:
module priority_encoder_16bit (
  input [15:0] req_bits,
  output reg [3:0] priority_out
);

  always @(req_bits)
  begin
    if (req_bits[15]) priority_out = 4'hF;
    else if (req_bits[14]) priority_out = 4'hE;
    else if (req_bits[13]) priority_out = 4'hD;
    else if (req_bits[12]) priority_out = 4'hC;
    else if (req_bits[11]) priority_out = 4'hB;
    else priority_out = 4'h0;
  end
endmodule

after_code:
module priority_encoder_16bit (
  input [15:0] req_bits,
  output reg [3:0] priority_out
);

  always @(*)
  begin
    if (req_bits[15]) priority_out = 4'hF;
    else if (req_bits[14]) priority_out = 4'hE;
    else if (req_bits[13]) priority_out = 4'hD;
    else if (req_bits[12]) priority_out = 4'hC;
    else if (req_bits[11]) priority_out = 4'hB;
    else priority_out = 4'h0;
  end
endmodule
